from django.test import TestCase, override_settings
from django.template import Template, Context
from django.utils.safestring import SafeString

class StaticTagTest(TestCase):

    @override_settings(STATIC_URL='/static/')
    def test_static_url_without_script_name(self):
        template = Template("{% load static %}{% static 'example.css' %}")
        context = Context({})
        rendered = template.render(context)
        self.assertIn('/static/example.css', rendered)

    @override_settings(STATIC_URL='/static/')
    def test_static_url_with_script_name(self):
        template = Template("{% load static %}{% static 'example.css' %}")
        context = Context({'request': type('Request', (object,), {'META': {'SCRIPT_NAME': '/app'}})})
        rendered = template.render(context)
        # Here we're testing what should happen if the function prepends SCRIPT_NAME
        expected_url = '/app/static/example.css'
        if isinstance(rendered, SafeString):
            self.assertIn(expected_url, str(rendered))
        else:
            self.fail("Expected a SafeString instance but got: {}".format(type(rendered)))

    @override_settings(STATIC_URL='/static/', SCRIPT_NAME='/app')
    def test_static_url_with_script_name_settings(self):
        template = Template("{% load static %}{% static 'example.css' %}")
        context = Context({'request': type('Request', (object,), {'META': {}})})
        rendered = template.render(context)
        # Ensuring SCRIPT_NAME addition even when not specifying in META, assuming settings is used
        expected_url = '/app/static/example.css'
        if isinstance(rendered, SafeString):
            self.assertIn(expected_url, str(rendered))
        else:
            self.fail("Expected a SafeString instance but got: {}".format(type(rendered)))

    @override_settings(STATIC_URL='/static/')
    def test_static_url_script_name_empty(self):
        template = Template("{% load static %}{% static 'example.css' %}")
        context = Context({'request': type('Request', (object,), {'META': {'SCRIPT_NAME': ''}})})
        rendered = template.render(context)
        # If SCRIPT_NAME is empty, it should not affect the URL
        expected_url = '/static/example.css'
        if isinstance(rendered, SafeString):
            self.assertIn(expected_url, str(rendered))
        else:
            self.fail("Expected a SafeString instance but got: {}".format(type(rendered)))
